import { unstable_cache } from "next/cache";

export type Post = {
  id: string;
  title: string;
  body: string;
  createdAt: Date;
};

// In-memory store (simulates a database)
const posts: Post[] = [
  {
    id: "1",
    title: "Welcome",
    body: "Welcome to the posts app!",
    createdAt: new Date("2026-01-01"),
  },
];

/**
 * Returns a cached copy of all posts, tagged with "posts".
 * The cache is revalidated when `revalidateTag("posts")` is called.
 */
export const getPosts = unstable_cache(
  async () => {
    return posts.map((p) => ({ ...p }));
  },
  ["posts-list"],
  { tags: ["posts"] }
);

/**
 * Adds a new post to the store and returns it.
 */
export async function addPost(title: string, body: string): Promise<Post> {
  const post: Post = {
    id: String(Date.now()),
    title,
    body,
    createdAt: new Date(),
  };
  posts.push(post);
  return post;
}

"use server";

import { revalidateTag } from "next/cache";
import { addPost } from "@/lib/posts";

export async function createPost(formData: FormData) {
  const title = formData.get("title") as string;
  const body = formData.get("body") as string;

  if (!title || !body) {
    throw new Error("Title and body are required");
  }

  await addPost(title, body);

  // Invalidate the "posts" cache tag so the next request fetches
  // fresh data instead of serving stale content.
  await revalidateTag("posts");
}

import { getPosts } from "@/lib/posts";
import { createPost } from "@/app/actions";

export default async function Home() {
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>

      <form action={createPost} style={{ marginBottom: "2rem" }}>
        <div>
          <label htmlFor="title">Title</label>
          <input id="title" name="title" placeholder="Post title" required />
        </div>
        <div>
          <label htmlFor="body">Body</label>
          <textarea id="body" name="body" placeholder="Post body" required />
        </div>
        <button type="submit">Create Post</button>
      </form>

      <ul>
        {posts.map((post) => (
          <li key={post.id}>
            <h2>{post.title}</h2>
            <p>{post.body}</p>
          </li>
        ))}
      </ul>
    </main>
  );
}

